// Inverted version for example 2
const EXAMPLE_FRAMES_INV = EXAMPLE_FRAMES.map(f => {
  const chars = " .'`^,:;Il!i><~+_-?][}{1)(|/tfjrxnuvczXYUJCLQ0OZmwqpdbkhao*#MW&8%B@$";
  const inv = chars.split("").reverse().join("");
  // rebuild frame replacing chars
  const activeOrig = chars;
  const activeInv = inv;
  return f.split("").map(ch => {
    const idx = activeOrig.indexOf(ch);
    return idx >= 0 ? activeInv[idx] : ch;
  }).join("");
});

// High-threshold version (lum=60 means more spaces)
const EXAMPLE_FRAMES_HI = EXAMPLE_FRAMES.map(f =>
  f.split("").map(ch => (" .'`".includes(ch) ? " " : ch)).join("")
);

// ── State ──
let userFrames = [];
let currentFrameIndex = 0;
let isPlaying = true;
let playInterval = null;
let currentColor = "green";
let isProcessing = false;
let cancelProcessing = false;

// ── Example Animations ──
let ex1Frame = 0, ex2Frame = 0, ex3Frame = 0;

function startExampleAnimations() {
  setInterval(() => {
    ex1Frame = (ex1Frame + 1) % EXAMPLE_FRAMES.length;
    document.getElementById("ex1").textContent = EXAMPLE_FRAMES[ex1Frame];
  }, 120);

  setInterval(() => {
    ex2Frame = (ex2Frame + 1) % EXAMPLE_FRAMES.length;
    document.getElementById("ex2").textContent = EXAMPLE_FRAMES_INV[ex2Frame];
  }, 140);

  setInterval(() => {
    ex3Frame = (ex3Frame + 1) % EXAMPLE_FRAMES.length;
    document.getElementById("ex3").textContent = EXAMPLE_FRAMES_HI[ex3Frame];
  }, 100);
}

// ── Hero background ──
function startHeroBg() {
  let f = 0;
  const el = document.getElementById("heroBgAscii");
  if (!el) return;
  setInterval(() => {
    f = (f + 1) % EXAMPLE_FRAMES.length;
    el.textContent = EXAMPLE_FRAMES[f];
  }, 80);
}

// ── Pixel → ASCII ──
function pixelsToAscii(data, width, height, lumThreshold, chars, invert) {
  let activeChars = chars;
  if (invert) activeChars = activeChars.split("").reverse().join("");

  const lumRange = Math.max(1, 255 - lumThreshold);
  let frame = "";

  for (let y = 0; y < height; y++) {
    for (let x = 0; x < width; x++) {
      const i = (y * width + x) * 4;
      const lum = 0.299 * data[i] + 0.587 * data[i + 1] + 0.114 * data[i + 2];

      if (lum < lumThreshold) {
        frame += " ";
        continue;
      }

      const charIndex = Math.floor(
        ((lum - lumThreshold) * (activeChars.length - 1)) / lumRange
      );
      frame += activeChars[Math.max(0, Math.min(charIndex, activeChars.length - 1))] || " ";
    }
    if (y < height - 1) frame += "\n";
  }
  return frame;
}

// ── Video Processing ──
async function processVideo(file) {
  const { cols: columns, lum: lumThr } = DETAIL_PRESETS[activeDetail];
  const fps     = SPEED_PRESETS[activeSpeed].fps;
  const charset = CHARSET_MAP[activeStyle] || CHARSET_MAP.standard;
  const invert  = activeInvert;

  return new Promise((resolve, reject) => {
    const video = document.createElement("video");
    video.muted = true;
    video.playsInline = true;
    video.preload = "metadata";
    video.src = URL.createObjectURL(file);

    video.addEventListener("error", () => reject(new Error("Failed to load video")));

    video.addEventListener("loadedmetadata", async () => {
      const duration  = video.duration;
      const vw        = video.videoWidth;
      const vh        = video.videoHeight;
      const outH      = Math.max(1, Math.round(vh * (columns / vw) * FONT_RATIO));

      const canvas    = document.createElement("canvas");
      canvas.width    = columns;
      canvas.height   = outH;
      const ctx       = canvas.getContext("2d", { willReadFrequently: true });

      const totalFrames = Math.max(1, Math.floor(duration * fps));
      const frames      = [];

      setProgress(0, `Processing frame 0 / ${totalFrames}`);

      for (let fi = 0; fi < totalFrames; fi++) {
        if (cancelProcessing) { resolve([]); return; }

        const time = fi / fps;
        await seekTo(video, Math.min(time, duration - 0.001));

        ctx.drawImage(video, 0, 0, columns, outH);
        const imageData = ctx.getImageData(0, 0, columns, outH);
        const ascii = pixelsToAscii(imageData.data, columns, outH, lumThr, charset, invert);
        frames.push(ascii);

        const pct = Math.round(((fi + 1) / totalFrames) * 100);
        setProgress(pct, `Processing frame ${fi + 1} / ${totalFrames}`);
      }

      URL.revokeObjectURL(video.src);
      resolve(frames);
    });
  });
}

function seekTo(video, time) {
  return new Promise(res => {
    const onSeeked = () => { video.removeEventListener("seeked", onSeeked); res(); };
    video.addEventListener("seeked", onSeeked);
    video.currentTime = time;
  });
}

// ── Progress UI ──
function setProgress(pct, text) {
  document.getElementById("progressFill").style.width = pct + "%";
  document.getElementById("progressText").textContent = text;
}

// ── Color map for export canvas ──
const COLOR_HEX = { green: "#00ff41", blue: "#79A4FF", pink: "#ff006e", white: "#e0e0e0" };

// ── Toast ──
let toastTimer = null;
function showToast(msg, type = "success") {
  const t = document.getElementById("toast");
  const icons = { success: "✓", error: "✗", info: "◈" };
  document.getElementById("toastIcon").textContent = icons[type] || "●";
  document.getElementById("toastMsg").textContent = msg;
  t.className = `toast ${type} show`;
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => { t.classList.remove("show"); }, 3000);
}

// ── Playback ──
function setFrames(frames) {
  userFrames = frames;
  currentFrameIndex = 0;
  showFrame(0);
  startPlayback();

  document.getElementById("placeholder").style.display = "none";
  document.getElementById("asciiOutput").style.display = "";
  document.getElementById("outputStatus").classList.add("visible");
  document.getElementById("exportBar").classList.add("visible");
}

function showFrame(idx) {
  const frames = userFrames.length ? userFrames : [];
  if (!frames.length) return;
  idx = ((idx % frames.length) + frames.length) % frames.length;
  currentFrameIndex = idx;
  document.getElementById("asciiOutput").textContent = frames[idx];
  document.getElementById("frameCounter").textContent = `${idx + 1} / ${frames.length}`;
}

function startPlayback() {
  stopPlayback();
  const fps = SPEED_PRESETS[activeSpeed].fps;
  playInterval = setInterval(() => {
    if (isPlaying && userFrames.length) {
      showFrame(currentFrameIndex + 1);
    }
  }, 1000 / fps);
  isPlaying = true;
  const btn = document.getElementById("playBtn");
  btn.textContent = "❚❚ PAUSE";
  btn.classList.add("active");
}

function stopPlayback() {
  if (playInterval) clearInterval(playInterval);
  playInterval = null;
}

function togglePlay() {
  isPlaying = !isPlaying;
  const btn = document.getElementById("playBtn");
  if (isPlaying) {
    btn.textContent = "❚❚ PAUSE";
    btn.classList.add("active");
  } else {
    btn.textContent = "► PLAY";
    btn.classList.remove("active");
  }
}

function stepFrame(dir) {
  isPlaying = false;
  const btn = document.getElementById("playBtn");
  btn.textContent = "► PLAY";
  btn.classList.remove("active");
  showFrame(currentFrameIndex + dir);
}

// ── Export: measure monospace char dimensions on a temp canvas ──
function measureMonoChar(fontSize) {
  const c = document.createElement("canvas");
  const x = c.getContext("2d");
  x.font = `${fontSize}px "Courier New", monospace`;
  const w = x.measureText("M").width;
  return { w, h: fontSize * 1.2 };
}

// ── Export: WebM video via canvas recording ──
async function exportWebM() {
  if (!userFrames.length) return;
  const btn = document.getElementById("btnWebm");
  const overlay = document.getElementById("recordingOverlay");
  const recText = document.getElementById("recordingText");
  const recSub  = document.getElementById("recordingSub");

  btn.disabled = true;
  overlay.classList.add("visible");
  stopPlayback();

  const fps      = SPEED_PRESETS[activeSpeed].fps;
  const fontSize = 10;
  const { w: cw, h: ch } = measureMonoChar(fontSize);
  const firstLines = userFrames[0].split("\n");
  const rows = firstLines.length;
  const cols = Math.max(...firstLines.map(l => l.length));
  const canvasW = Math.round(cols * cw);
  const canvasH = Math.round(rows * ch);

  const canvas = document.createElement("canvas");
  canvas.width  = canvasW;
  canvas.height = canvasH;
  const ctx = canvas.getContext("2d");
  const textColor = COLOR_HEX[currentColor] || "#00ff41";
  const bgColor   = "#080808";

  // Check codec support
  const mimeType = MediaRecorder.isTypeSupported("video/webm;codecs=vp9")
    ? "video/webm;codecs=vp9"
    : "video/webm";

  const stream   = canvas.captureStream(fps);
  const recorder = new MediaRecorder(stream, { mimeType, videoBitsPerSecond: 8_000_000 });
  const chunks   = [];
  recorder.ondataavailable = e => { if (e.data.size > 0) chunks.push(e.data); };

  recorder.start();

  const msPerFrame = Math.round(1000 / fps);
  const total = userFrames.length;

  for (let fi = 0; fi < total; fi++) {
    const lines = userFrames[fi].split("\n");
    ctx.fillStyle = bgColor;
    ctx.fillRect(0, 0, canvasW, canvasH);
    ctx.fillStyle = textColor;
    ctx.font = `${fontSize}px "Courier New", monospace`;
    ctx.textBaseline = "top";
    for (let li = 0; li < lines.length; li++) {
      ctx.fillText(lines[li], 0, li * ch);
    }
    recText.textContent = `Rendering frame ${fi + 1} / ${total}`;
    recSub.textContent  = `${Math.round(((fi + 1) / total) * 100)}% complete`;
    await new Promise(r => setTimeout(r, msPerFrame));
  }

  recorder.stop();
  await new Promise(r => { recorder.onstop = r; });

  const blob = new Blob(chunks, { type: mimeType });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = "ascii-animation.webm";
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 5000);

  overlay.classList.remove("visible");
  btn.disabled = false;
  startPlayback();
  showToast("Video downloaded!", "success");
}

// ── Export: self-contained HTML embed snippet ──
function copyEmbedCode() {
  if (!userFrames.length) return;

  const fps    = SPEED_PRESETS[activeSpeed].fps;
  const color  = COLOR_HEX[currentColor] || "#00ff41";
  const uid    = "av" + Date.now().toString(36);
  const ms     = Math.round(1000 / fps);

  // Encode frames as a compact JSON array embedded directly in the script
  const framesJson = JSON.stringify(userFrames);

  const snippet = `<!-- ASCII2Video Embed — paste anywhere in your HTML -->
<div style="background:#080808;border-radius:10px;overflow:auto;display:inline-block;padding:1rem 1.25rem;max-width:100%">
  <pre id="${uid}" style="font:10px/1.2 'Courier New',Courier,monospace;color:${color};white-space:pre;margin:0;"></pre>
</div>
<script>
(function(){
  var f=${framesJson};
  var i=0,e=document.getElementById("${uid}");
  if(!e)return;
  e.textContent=f[0];
  setInterval(function(){e.textContent=f[i=(i+1)%f.length];},${ms});
})();
<\/script>`;

  navigator.clipboard.writeText(snippet)
    .then(() => showToast("Embed code copied to clipboard!", "info"))
    .catch(() => {
      // Fallback: show in a prompt so user can copy manually
      const ta = document.createElement("textarea");
      ta.value = snippet;
      document.body.appendChild(ta);
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
      showToast("Embed code copied!", "info");
    });
}

// ── Export: raw JSON frame data ──
function downloadJson() {
  if (!userFrames.length) return;
  const data = JSON.stringify({
    fps:    SPEED_PRESETS[activeSpeed].fps,
    detail: DETAIL_PRESETS[activeDetail].label,
    style:  activeStyle,
    color:  COLOR_HEX[currentColor] || "#00ff41",
    frames: userFrames,
  }, null, 2);
  const blob = new Blob([data], { type: "application/json" });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement("a");
  a.href     = url;
  a.download = "ascii-frames.json";
  a.click();
  setTimeout(() => URL.revokeObjectURL(url), 5000);
  showToast("JSON downloaded!", "success");
}

// ── Export button listeners ──
document.getElementById("btnWebm").addEventListener("click", exportWebM);
document.getElementById("btnEmbed").addEventListener("click", copyEmbedCode);
document.getElementById("btnJson").addEventListener("click", downloadJson);

// ── Color picker ──
document.querySelectorAll(".color-dot").forEach(dot => {
  dot.addEventListener("click", () => {
    document.querySelectorAll(".color-dot").forEach(d => d.classList.remove("active"));
    dot.classList.add("active");
    const color = dot.dataset.color;
    currentColor = color;
    const out = document.getElementById("asciiOutput");
    out.className = color === "green" ? "" : color;
  });
});

// ── File handling ──
const dropZone   = document.getElementById("dropZone");
const fileInput  = document.getElementById("fileInput");
const processBtn = document.getElementById("processBtn");
const dropIcon   = document.getElementById("dropIcon");
const dropText   = document.getElementById("dropText");
const dropFmts   = document.getElementById("dropFormats");
let selectedFile = null;

// A single persistent click listener — always targets the same fileInput element
dropZone.addEventListener("click", () => fileInput.click());

dropZone.addEventListener("dragover", e => {
  e.preventDefault();
  dropZone.classList.add("drag-over");
});

dropZone.addEventListener("dragleave", () => dropZone.classList.remove("drag-over"));

dropZone.addEventListener("drop", e => {
  e.preventDefault();
  dropZone.classList.remove("drag-over");
  const file = e.dataTransfer.files[0];
  if (file && file.type.startsWith("video/")) {
    setSelectedFile(file);
  } else {
    showDropError("Please drop a video file");
  }
});

fileInput.addEventListener("change", e => {
  const file = e.target.files[0];
  if (file) setSelectedFile(file);
});

function setSelectedFile(file) {
  selectedFile = file;
  const size = (file.size / 1024 / 1024).toFixed(1);
  // Update in-place so the fileInput element stays in the DOM
  dropIcon.textContent = "▶";
  dropText.innerHTML = `<strong>${escHtml(file.name)}</strong><br>${size} MB — ready to process`;
  dropFmts.textContent = 'Adjust settings, then click "PROCESS VIDEO"';
  processBtn.disabled = false;
}

function showDropError(msg) {
  const prev = dropText.innerHTML;
  dropText.innerHTML = `<span style="color:var(--pink)">${msg}</span>`;
  setTimeout(() => { dropText.innerHTML = prev; }, 2000);
}

function escHtml(s) {
  return s.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
}

// ── Process button ──
processBtn.addEventListener("click", async () => {
  if (isProcessing) {
    cancelProcessing = true;
    return;
  }
  if (!selectedFile) return;

  isProcessing = true;
  cancelProcessing = false;
  processBtn.textContent = "CANCEL";
  processBtn.classList.add("cancel");

  document.getElementById("progressWrap").classList.add("visible");
  document.getElementById("outputTitle").textContent = selectedFile.name;
  stopPlayback();

  try {
    const frames = await processVideo(selectedFile);
    if (!cancelProcessing && frames.length > 0) {
      setFrames(frames);
    } else if (cancelProcessing) {
      document.getElementById("progressText").textContent = "Cancelled";
    }
  } catch (err) {
    document.getElementById("progressText").textContent = "Error: " + err.message;
    console.error(err);
  }

  setTimeout(() => {
    document.getElementById("progressWrap").classList.remove("visible");
  }, 1500);

  isProcessing = false;
  cancelProcessing = false;
  processBtn.textContent = "PROCESS VIDEO";
  processBtn.classList.remove("cancel");
});

// ── Detail Level ──
document.getElementById("detailTrack").addEventListener("click", e => {
  const step = e.target.closest(".detail-step");
  if (!step) return;
  activeDetail = parseInt(step.dataset.idx);
  document.querySelectorAll(".detail-step").forEach((s, i) =>
    s.classList.toggle("active", i === activeDetail)
  );
  document.getElementById("detailDesc").textContent = DETAIL_PRESETS[activeDetail].desc;
});

// ── Animation Speed ──
document.getElementById("speedPills").addEventListener("click", e => {
  const pill = e.target.closest(".speed-pill");
  if (!pill) return;
  activeSpeed = parseInt(pill.dataset.idx);
  document.querySelectorAll(".speed-pill").forEach((p, i) =>
    p.classList.toggle("active", i === activeSpeed)
  );
  document.getElementById("speedDesc").textContent = SPEED_PRESETS[activeSpeed].desc;
  // Update playback speed live if already playing
  if (userFrames.length) startPlayback();
});

// ── Art Style ──
document.getElementById("styleGrid").addEventListener("click", e => {
  const card = e.target.closest(".style-card");
  if (!card) return;
  activeStyle = card.dataset.style;
  document.querySelectorAll(".style-card").forEach(c =>
    c.classList.toggle("active", c === card)
  );
});

// ── Brightness Mode (invert) ──
document.getElementById("invertSeg").addEventListener("click", e => {
  const btn = e.target.closest(".invert-btn");
  if (!btn) return;
  activeInvert = btn.dataset.invert === "true";
  document.querySelectorAll(".invert-btn").forEach(b =>
    b.classList.toggle("active", b === btn)
  );
});

// ── Intersection Observer for fade-ins ──
const observer = new IntersectionObserver(entries => {
  entries.forEach(e => { if (e.isIntersecting) e.target.classList.add("visible"); });
}, { threshold: 0.1 });
document.querySelectorAll(".fade-in").forEach(el => observer.observe(el));

// ── Boot ──
startHeroBg();
startExampleAnimations();
